+                try self.emitComparison(stack, "<");
+                try self.write(") {\n");
+            },
+
+            .lte => {
+                try self.write("    if (");
+                try self.emitComparison(stack, "<=");
+                try self.write(") {\n");
+            },
+
+            .gt => {
+                try self.write("    if (");
+                try self.emitComparison(stack, ">");
+                try self.write(") {\n");
+            },
+
+            .gte => {
+                try self.write("    if (");
+                try self.emitComparison(stack, ">=");
+                try self.write(") {\n");
+            },
+
+            // Conditional branches
+            .if_false, .if_false8 => {
+                const target = instr.getJumpTarget() orelse 0;
+                const target_block = self.cfg.pc_to_block.get(target) orelse 0;
